import json
import hashlib
from pydantic import BaseModel, Field, ValidationError
from typing import Optional

class ClassificationResult(BaseModel):
    label: str
    confidence: float = Field(ge=0.0, le=1.0)
    reasoning: str

class RetryExhausted(Exception):
    pass

def parse_with_retry(raw_text, model_cls, record, schema_str, max_retries=2):
    last_error = None
    raw = raw_text
    for attempt in range(1 + max_retries):
        cleaned = raw.strip()
        if cleaned.startswith("```"):
            cleaned = cleaned.split("\n", 1)[-1].rsplit("```", 1)[0].strip()
        try:
            obj = json.loads(cleaned)
            return model_cls.model_validate(obj)
        except (json.JSONDecodeError, ValidationError, ValueError) as exc:
            last_error = exc
            if attempt < max_retries:
                correction_prompt = (
                    f"Your previous response failed validation.\n"
                    f"ERROR: {type(exc).__name__}: {exc}\n"
                    f"YOUR OUTPUT: {raw[:200]}\n"
                    f"RECORD: {json.dumps(record)}\n"
                    f"SCHEMA: {schema_str}\n"
                    f"Fix and return ONLY the corrected JSON."
                )
                raw = llm_query(correction_prompt)
    raise RetryExhausted(f"Failed after {1 + max_retries} attempts. Last: {last_error}")

# --- Deduplication Ring ---
class DeduplicationRing:
    def __init__(self):
        self._hashes = set()
    def content_hash(self, record):
        canonical = json.dumps(record, sort_keys=True, default=str)
        return hashlib.sha256(canonical.encode()).hexdigest()
    def is_duplicate(self, record):
        return self.content_hash(record) in self._hashes
    def mark_processed(self, record):
        self._hashes.add(self.content_hash(record))
    def deduplicate_batch(self, records):
        unique, skipped = [], 0
        for r in records:
            if self.is_duplicate(r):
                skipped += 1
            else:
                unique.append(r)
        return unique, skipped

record = {"id": "R-1", "text": "Aspirin 100mg"}
schema_str = json.dumps(ClassificationResult.model_json_schema(), indent=2)

# This first call will return bad JSON, triggering a retry
first_response = llm_query(
    f"Classify this record as JSON matching schema:\n{schema_str}\nRecord: {json.dumps(record)}"
)

result = parse_with_retry(first_response, ClassificationResult, record, schema_str, max_retries=1)
print(f"Parse succeeded after retry: {result.label}, conf={result.confidence}")

# --- Test dedup ring ---
dedup = DeduplicationRing()
batch = [
    {"id": "R-1", "text": "Aspirin 100mg"},
    {"id": "R-2", "text": "Ibuprofen 200mg"},
    {"id": "R-1", "text": "Aspirin 100mg"},
    {"id": "R-3", "text": "Paracetamol 500mg"},
    {"id": "R-2", "text": "Ibuprofen 200mg"}
]
for r in batch[:3]:
    dedup.mark_processed(r)

unique, skipped = dedup.deduplicate_batch(batch)
print(f"Dedup: {len(unique)} unique, {skipped} skipped out of {len(batch)}")
print(f"Ring size: {len(dedup._hashes)}")
